issue_comment_body:
My stab at dynamic loading X11 for glx: https://gist.github.com/BlGene/a3d3318e57de94f89d98dabcb430c785

It would be nice to make the generated code `-Wall -Wstrict-prototypes` compatible.  This also required the following change to gl.c:
```
@@ -2214,8 +2214,6 @@ static int get_exts( int version, const char **out_exts, int *out_num_exts_i, co
         glGetIntegerv(GL_NUM_EXTENSIONS, &num_exts_i);
         if (num_exts_i > 0) {
             exts_i = (const char **)malloc(num_exts_i * sizeof *exts_i);
-        } else {
-            exts_i = NULL;
         }
         if (exts_i == NULL) {
             return 0;
```

@davisking you are saying absolutely right things, I think it's all clear for me. But I'm trying to understand something much more simpler. 
I want to use tt::add() function, for this I need two tensors with num_samples() == 1, so can I extract only one sample from the output_tensor()? I already saw set_sample() function, so maybe I can find something like get_sample()? If I can't do it using tensor, can I convert tensor to matrix using mat() function and then extract only one sample? Or iterating over host() will be only one solution for this purpose at the moment(until I make my own)?
Regards!

Привет!

Думаю, что беда состоит в следующем:

там, где происходит чтение из таблиц (txt-файлов c числами) готовой
функцией, то всё хорошо,
но при парсинге параметра для опкода он должен считать из отдельного файла
(Maps) тип переменной и идентификатор таблицы, пример: параметр имеет тип
напрямую указываемый и ссылается на таблицу с мидишными кодами
это выглядит в map-файле так: d MID000. Пример из листинга, где парсится
параметр:

ParameterType: d
TableName: MID000; TableID = 24
22 -> 22.000

B всё отлично для первого параметра, но следующему параметру он даже тип
назначить верно не может

ParameterType: 0
TableName: ; TableID = 0
0 -> -2054565793904463970304.000

или

ParameterType: 0
TableName: ; TableID = 0
26 -> 0.000

Как мне кажется при чтении map-файлов под твоей операционкой не
распазнается переход на новую строку в txt-файле и поэтому 2-ой и далее
параметры не парсятся

Чтение map-файла происходит в файле GenInstrumentContent.с

С 225 строки:

{

        if((TempFile = fopen(TempModuleMap,"rb")) == NULL)
        {
            printf("Error - ");
            printf(TempModuleMap);
            printf(" not opened!\n");
            return 0;
        }
        else
        {
            printf("Number of real parameters = ");
            printf("%d\n",ParameterCountersVA[ModuleCounter]);
            printf("ModuleCounter = ");
            printf("%d\n",ModuleCounter);
            printf("ModuleIndex = ");
            printf("%d\n",ModuleIndexListVA[ModuleCounter]);
            printf("ModuleType = ");
            printf("%d\n",ModuleListVA[ModuleCounter]);


            fseek(TempFile, 0, SEEK_SET);

            //printf("Direct Parameters\n");

            for(i=0;i<ParameterCountersVA[ModuleCounter];i++)
            {

                fread(&Maptemp,1,1,TempFile);

                ParameterType[i]=Maptemp;

                if(Maptemp==0)
                {
                    break;
                }

                if((Maptemp==100)||(Maptemp==104)) // d or h
                {

                    fread(&Maptemp,1,1,TempFile); // space or tab

                    fread(&Maptemp6,1,6,TempFile);
                    for(j=0;j<256;j++)
                    {
                        for(k=0;k<6;k++)
                        {
                            Nametemp6[k]=NamesMapTables[k][j];
                        }

                        if(memcmp(Maptemp6,Nametemp6,6)==0)
                        {
                            mapid=j;

                            MapTablesVA[ModuleCounter][i]=mapid;
                            valueINT=ParametersVA[ModuleCounter][i];
                            value[i]=Tables[valueINT][mapid];

                            break;

                        }
                    }
                }

                while(true)
                {
                    if(fread(&Maptemp,1,1,TempFile)==0)
                    {
                        break;
                    }
                    if(Maptemp==13)
                    {
                        fread(&Maptemp,1,1,TempFile);
                        break;
                    }

                }

            }

            //printf("Selected Parameters\n");

            fseek(TempFile, 0, SEEK_SET);
            for(i=0;i<ParameterCountersVA[ModuleCounter];i++)
            {
                fread(&Maptemp,1,1,TempFile);

                if(Maptemp==115)
                {
                    fread(&Maptemp,1,1,TempFile); // space or tab

                    SelectorID=0;
                    while(true)
                    {
                        fread(&Maptemp,1,1,TempFile);

if((Maptemp==13)||(Maptemp==9)||(Maptemp==32)||(Maptemp==0))
                        {
                            break;
                        }
                        SelectorID=SelectorID*10+(Maptemp-48);
                    }

                    TablesPointer=(unsigned int)(value[SelectorID-1]);

                    for(j=0;j<TablesPointer+1;j++)
                    {
                        fread(&Maptemp6,1,6,TempFile);
                        fread(&Maptemp,1,1,TempFile);
                    }

                    for(j=0;j<256;j++)
                    {
                        for(k=0;k<6;k++)
                        {
                            Nametemp6[k]=NamesMapTables[k][j];
                        }

                        if(memcmp(Maptemp6,Nametemp6,6)==0)
                        {
                            mapid=j;

                            MapTablesVA[ModuleCounter][i]=mapid;
                            valueINT=ParametersVA[ModuleCounter][i];
                            value[i]=Tables[valueINT][mapid];

                            break;

                        }
                    }
                }

                while(true)
                {
                    if(fread(&Maptemp,1,1,TempFile)==0)
                    {
                        break;
                    }
                    if(Maptemp==13)
                    {
                        fread(&Maptemp,1,1,TempFile);
                        break;
                    }

                }

            }

            // And let set the w-map parameters (Section of Delays)
            //

            fseek(TempFile, 0, SEEK_SET);
            for(i=0;i<ParameterCountersVA[ModuleCounter];i++)
            {
                fread(&Maptemp,1,1,TempFile);

                if(Maptemp==119) // if find w-type parameter
                {
                    fread(&Maptemp,1,1,TempFile); // space or tab

                    SelectorID=0; // first selector. His value most be only
"0" or "1"
                    while(true)
                    {
                        fread(&Maptemp,1,1,TempFile);

if((Maptemp==13)||(Maptemp==9)||(Maptemp==32)||(Maptemp==0))
                        {
                            break;
                        }
                        SelectorID=SelectorID*10+(Maptemp-48);
                    }

                    SelectorIDadd=0; // second selector
                    while(true)
                    {
                        fread(&Maptemp,1,1,TempFile);

if((Maptemp==13)||(Maptemp==9)||(Maptemp==32)||(Maptemp==0))
                        {
                            break;
                        }
                        SelectorIDadd=SelectorIDadd*10+(Maptemp-48);
                    }

                    TablesPointer=(unsigned
int)(value[SelectorID-1])*(unsigned int)(value[SelectorIDadd-1]);

                    for(j=0;j<TablesPointer+1;j++)
                    {
                        fread(&Maptemp6,1,6,TempFile);
                        fread(&Maptemp,1,1,TempFile);
                    }

                    for(j=0;j<256;j++)
                    {
                        for(k=0;k<6;k++)
                        {
                            Nametemp6[k]=NamesMapTables[k][j];
                        }

                        if(memcmp(Maptemp6,Nametemp6,6)==0)
                        {
                            mapid=j;

                            MapTablesVA[ModuleCounter][i]=mapid;
                            valueINT=ParametersVA[ModuleCounter][i];
                            value[i]=Tables[valueINT][mapid];

                            break;

                        }
                    }
                }

                while(true)
                {
                    if(fread(&Maptemp,1,1,TempFile)==0)
                    {
                        break;
                    }
                    if(Maptemp==13)
                    {
                        fread(&Maptemp,1,1,TempFile);
                        break;
                    }

                }

            }

        }
        //printf("ModuleCounter: ");
        //printf("%d\n",ModuleCounter);

        printf("ParameterCountersVA: ");
        printf("%d\n",ParameterCountersVA[ModuleCounter]);

        for(i=0;i<ParameterCountersVA[ModuleCounter];i++)
        {
            mapid=MapTablesVA[ModuleCounter][i];

            printf("ParameterType: ");
            printf("%c\n",ParameterType[i]);

            for(k=0;k<6;k++)
            {
                Nametemp6[k]=NamesMapTables[k][mapid];
            }

            printf("TableName: ");
            for(k=0;k<6;k++)
            {
                printf("%c",Nametemp6[k]);
            }

            printf("; ");
            printf("TableID = ");
            printf("%d\n",mapid);

            printf("%d",ParametersVA[ModuleCounter][i]);
            printf(" -> ");
            printf("%1.3f\n",value[i]);


            if(ParameterType[i]!=104) // h - we hide parameter in
new.csd-file
            {
                fprintf(NewFile,"%1.3f",value[i]);
                PPflag=true;

if((i!=ParameterCountersVA[ModuleCounter]-1)&&(ParameterType[i+1]!=104))
                {
                    fprintf(NewFile,", ");
                }
            }

        }

