@nitrag another example of using Cognito is in the [Ionic AWS Starter](https://github.com/ionic-team/ionic2-starter-aws). They give a lot of nice setup for getting a session. Then you can access the token directly and make API calls with `session.getIdToken().getJwtToken();` just like in the [user.ts](https://github.com/ionic-team/ionic2-starter-aws/blob/master/src/providers/user.ts#L134) file (I modified this to return the session object so that I have access to all tokens as needed). Something like:
```
import {Injectable} from "@angular/core";
import {Http, Headers, RequestOptions} from "@angular/http";
import 'rxjs/add/operator/map';
import {User} from "./user";

declare var AWS: any;
declare var AWSCognito: any;

@Injectable()
export class MyProvider {
  url;
  headers;
  options;

  constructor(public http: Http, public user: User) {
    console.log('Hello My Provider');
    this.url = 'https://MY_CHALICE_PREFIX.execute-api.us-west-2.amazonaws.com/api';
    this.headers = new Headers();
    user.isAuthenticated().then((res: any) => {
      this.headers.append('Authorization', res.getIdToken().getJwtToken());
      this.options = new RequestOptions({headers: this.headers})
    });

  }

  getMyPermissions() {
    return this.http.get(this.url + '/auth/my_permissions', this.options)
      .map(res => res.json())
  }

}

```

